amends "package://github.com/jdx/hk/releases/download/v1.40.0/hk@1.40.0#/Config.pkl"

import "package://github.com/jdx/hk/releases/download/v1.40.0/hk@1.40.0#/Builtins.pkl"

local allSteps = new Mapping<String, Step> {
  // formatters
  ["dprint"] = Builtins.dprint

  // linters
  ["detekt"] {
    glob = List("**/src/commonMain/kotlin/**/*.kt")
    check = "./gradlew detekt"
    exclusive = true
  }

  // generators
  ["abi-dump"] {
    glob = List("**/src/commonMain/kotlin/**/*.kt", "**/api/*.api", "**/api/*.klib.api")
    check = "./gradlew checkKotlinAbi"
    fix = "./gradlew updateKotlinAbi"
    exclusive = true
  }
}

hooks {
  ["pre-commit"] {
    fix = true
    stash = "git"
    steps {
      ...allSteps
    }
  }
  ["check"] {
    steps {
      ...allSteps
    }
  }
  ["fix"] {
    fix = true
    steps {
      ...allSteps
    }
  }
}

import dev.detekt.gradle.extensions.FailOnSeverity
import org.jetbrains.kotlin.gradle.dsl.abi.ExperimentalAbiValidation

plugins {
  id("multiplatform-module")
  id("org.jetbrains.dokka")
  id("com.vanniktech.maven.publish")
  id("org.jetbrains.kotlinx.kover")
  id("semver")
  id("dev.detekt")
}

group = "dev.sargunv.mobility-data"

kotlin {
  explicitApi()
  compilerOptions {
    freeCompilerArgs.add(
      // Will be the default soon: https://youtrack.jetbrains.com/issue/KT-11914
      "-Xconsistent-data-class-copy-visibility"
    )
  }
  abiValidation {
    @OptIn(ExperimentalAbiValidation::class)
    enabled = true
  }
}

detekt {
  source.setFrom("src/commonMain/kotlin", "src/ktorMain/kotlin")
  config.setFrom(rootProject.file("detekt.yml"))
  failOnSeverity = FailOnSeverity.Warning
  basePath.set(rootProject.rootDir)
}

dokka {
  dokkaSourceSets {
    configureEach {
      includes.from("MODULE.md")
      sourceLink {
        remoteUrl("https://github.com/sargunv/mobility-data-kt/tree/v${project.version}/")
        localDirectory = rootDir
      }
      externalDocumentationLinks {
        create("kotlinx-serialization") { url("https://kotlinlang.org/api/kotlinx.serialization/") }
        create("ktor") { url("https://api.ktor.io") }
      }
    }
  }
}

mavenPublishing {
  publishToMavenCentral(automaticRelease = true)
  if (providers.gradleProperty("signingInMemoryKey").isPresent) {
    signAllPublications()
  }

  pom {
    url = "https://github.com/sargunv/mobility-data-kt/"

    scm {
      url = "https://github.com/sargunv/mobility-data-kt"
      connection = "scm:git:git://github.com/sargunv/mobility-data-kt.git"
      developerConnection = "scm:git:git://github.com/sargunv/mobility-data-kt.git"
    }

    licenses {
      license {
        name = "Apache-2.0"
        url = "https://opensource.org/licenses/Apache-2.0"
        distribution = "repo"
      }
    }

    developers {
      developer {
        id = "sargunv"
        name = "Sargun Vohra"
      }
    }
  }
}

